# -*- coding: utf-8 -*-
import csv

questions = [
  {"id":"4059","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Potenciacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O valor de 2^10 e:","alternativa_a":"1024","alternativa_b":"512","alternativa_c":"2048","alternativa_d":"100","alternativa_e":"20","resposta_correta":"a","explicacao":"2^10 = 1024. Memorize: 2^1=2, 2^2=4, 2^3=8, 2^4=16, 2^5=32, 2^6=64, 2^7=128, 2^8=256, 2^9=512, 2^10=1024.","resposta":""},
  {"id":"4060","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Fatorial","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O valor de 5! (cinco fatorial) e:","alternativa_a":"120","alternativa_b":"25","alternativa_c":"60","alternativa_d":"24","alternativa_e":"720","resposta_correta":"a","explicacao":"5! = 5 x 4 x 3 x 2 x 1 = 120.","resposta":""},
  {"id":"4061","tipo":"multipla","disciplina":"Matematica","tema":"Combinatoria","subtema":"Arranjo simples","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"De quantas maneiras podemos eleger presidente e vice entre 6 candidatos?","alternativa_a":"30","alternativa_b":"15","alternativa_c":"36","alternativa_d":"12","alternativa_e":"720","resposta_correta":"a","explicacao":"A(6,2) = 6!/(6-2)! = 6!/4! = 6x5 = 30.","resposta":""},
  {"id":"4062","tipo":"multipla","disciplina":"Matematica","tema":"Estatistica","subtema":"Moda e mediana","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"No conjunto {3, 5, 5, 7, 9, 9, 9}, a moda e:","alternativa_a":"9","alternativa_b":"5","alternativa_c":"7","alternativa_d":"3","alternativa_e":"Amodal","resposta_correta":"a","explicacao":"A moda e o valor que aparece com maior frequencia. O numero 9 aparece 3 vezes (maior frequencia), enquanto 5 aparece 2 vezes e os demais 1 vez.","resposta":""},
  {"id":"4063","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Perimetro","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um retangulo tem lados de 4 cm e 6 cm. Seu perimetro e:","alternativa_a":"20 cm","alternativa_b":"24 cm","alternativa_c":"10 cm","alternativa_d":"12 cm","alternativa_e":"48 cm","resposta_correta":"a","explicacao":"Perimetro = 2(l + a) = 2(4 + 6) = 2 x 10 = 20 cm.","resposta":""},
  {"id":"4064","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Atrito","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um bloco de 5 kg repousa numa superficie horizontal. O coeficiente de atrito estatico e 0,4 e g=10 m/s2. A forca maxima de atrito estatico e:","alternativa_a":"20 N","alternativa_b":"0,4 N","alternativa_c":"50 N","alternativa_d":"2 N","alternativa_e":"12,5 N","resposta_correta":"a","explicacao":"Fatrito_max = mi_e x N = mi_e x m x g = 0,4 x 5 x 10 = 20 N.","resposta":""},
  {"id":"4065","tipo":"multipla","disciplina":"Fisica","tema":"Termodinamica","subtema":"Dilatacao termica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma barra de aco de 2 m de comprimento e aquecida de 20C a 120C. O coeficiente de dilatacao linear e 12x10^-6 /C. O aumento de comprimento e:","alternativa_a":"0,0024 m","alternativa_b":"0,024 m","alternativa_c":"0,24 m","alternativa_d":"2,4 m","alternativa_e":"0,00024 m","resposta_correta":"a","explicacao":"DeltaL = L0 x alfa x DeltaT = 2 x 12x10^-6 x 100 = 2400x10^-6 = 0,0024 m.","resposta":""},
  {"id":"4066","tipo":"multipla","disciplina":"Fisica","tema":"Ondulatoria","subtema":"Efeito Doppler","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O Efeito Doppler sonoro ocorre quando:","alternativa_a":"Ha movimento relativo entre a fonte sonora e o observador, alterando a frequencia percebida","alternativa_b":"O som e refletido por uma superficie","alternativa_c":"Duas ondas sonoras se encontram e se somam","alternativa_d":"O som passa por um meio mais denso","alternativa_e":"A amplitude da onda aumenta com a distancia","resposta_correta":"a","explicacao":"O Efeito Doppler: quando fonte e observador se aproximam, a frequencia percebida e maior (som mais agudo); quando se afastam, a frequencia percebida e menor (som mais grave). Aplica-se tambem a luz (desvio para o azul = aproximacao; desvio para o vermelho = afastamento) e e usado em radar, ultrassom medico e astronomia.","resposta":""},
  {"id":"4067","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Circuitos eletricos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Dois resistores de 6 ohms sao ligados em paralelo. A resistencia equivalente e:","alternativa_a":"3 ohms","alternativa_b":"12 ohms","alternativa_c":"6 ohms","alternativa_d":"1 ohm","alternativa_e":"36 ohms","resposta_correta":"a","explicacao":"Para resistores identicos em paralelo: Req = R/n = 6/2 = 3 ohms. Ou pela formula geral: 1/Req = 1/6 + 1/6 = 2/6, Req = 3 ohms.","resposta":""},
  {"id":"4068","tipo":"multipla","disciplina":"Fisica","tema":"Eletromagnetismo","subtema":"Forca magnetica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma carga positiva de 2 C move-se a 3 m/s num campo magnetico de 4 T (perpendicular). A forca magnetica sobre a carga e:","alternativa_a":"24 N","alternativa_b":"12 N","alternativa_c":"6 N","alternativa_d":"8 N","alternativa_e":"24 T","resposta_correta":"a","explicacao":"F = q * v * B * sen(90) = 2 x 3 x 4 x 1 = 24 N.","resposta":""},
  {"id":"4069","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Solubilidade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Semelhante dissolve semelhante e o principio que explica por que:","alternativa_a":"Substancias polares dissolvem substancias polares e apolares dissolvem apolares","alternativa_b":"A agua dissolve todos os compostos organicos","alternativa_c":"O benzeno e miscivel em agua","alternativa_d":"Substancias ionicas nao se dissolvem em agua","alternativa_e":"Todos os gases sao solúveis em agua","resposta_correta":"a","explicacao":"O principio 'like dissolves like' (semelhante dissolve semelhante): solventes polares (agua) dissolvem solutos polares e ionicos; solventes apolares (benzeno, hexano) dissolvem solutos apolares. Agua nao dissolve bem gorduras (apolares) porque as interacoes agua-agua (H) sao muito mais fortes que agua-gordura.","resposta":""},
  {"id":"4070","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Combustao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Na combustao completa de hidrocarbonetoss os produtos sao sempre:","alternativa_a":"CO2 e H2O","alternativa_b":"CO e H2O","alternativa_c":"C e H2","alternativa_d":"CO2 e H2","alternativa_e":"CO e CO2","resposta_correta":"a","explicacao":"Na combustao COMPLETA de hidrocarbonetos (com excesso de oxigenio), todo o carbono se oxida a CO2 e todo o hidrogenio a H2O. Exemplo: CH4 + 2O2 -> CO2 + 2H2O. Na combustao incompleta (falta de O2) forma-se CO (monoxido de carbono) e/ou C (fuligem).","resposta":""},
  {"id":"4071","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Propriedades coligativas","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A adicao de sal (NaCl) a agua provoca o abaixamento do ponto de congelamento porque:","alternativa_a":"Os ions dissolvidos dificultam a formacao da estrutura cristalina do gelo (crioscopia)","alternativa_b":"O sal aquece a agua por reacao exotermica","alternativa_c":"O sal remove o oxigenio dissolvido na agua","alternativa_d":"Os ions Na+ e Cl- aumentam a viscosidade da agua","alternativa_e":"A agua se torna mais densa com o sal","resposta_correta":"a","explicacao":"A crioscopia e uma propriedade coligativa: a presenca de soluto (eletrolito como NaCl) abaixa o ponto de congelamento. DeltaTf = Kf x m x i (onde i = fator de Van't Hoff). O NaCl dissocia em 2 ions, dobrando o efeito. Os ions perturbam a rede cristalina do gelo, necessitando temperatura mais baixa para solidificar.","resposta":""},
  {"id":"4072","tipo":"multipla","disciplina":"Biologia","tema":"Genetica","subtema":"Ligacao e permutacao","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Genes localizados no mesmo cromossomo tendem a ser herdados juntos, fenomeno chamado de:","alternativa_a":"Ligacao genica (linkage)","alternativa_b":"Epistasia","alternativa_c":"Pleiotropia","alternativa_d":"Codominancia","alternativa_e":"Penetrancia incompleta","resposta_correta":"a","explicacao":"A ligacao genica (linkage) ocorre quando genes estao no mesmo cromossomo (genes ligados) e tendem a ser herdados conjuntamente, violando a Segunda Lei de Mendel (segregacao independente). O crossing-over (permutacao) durante a meiose pode separar genes ligados, criando recombinantes. A frequencia de recombinacao mede a distancia entre genes (mapa genetico).","resposta":""},
  {"id":"4073","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Respiracao celular","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Na respiracao celular aerobia, a etapa que ocorre na mitocondria e produz a maior quantidade de ATP e:","alternativa_a":"Ciclo de Krebs e fosforilacao oxidativa (cadeia respiratoria)","alternativa_b":"Glicose","alternativa_c":"Fermentacao latica","alternativa_d":"Fotossintese","alternativa_e":"Glicolise","resposta_correta":"a","explicacao":"A respiracao aerobia tem tres etapas: glicolise (citoplasma, 2 ATP), ciclo de Krebs (mitocondria, 2 ATP) e cadeia respiratoria/fosforilacao oxidativa (membrana interna mitocondrial, ~32-34 ATP). O rendimento total e ~36-38 ATP por molecula de glicose. A cadeia respiratoria usa o gradiente de protons para sintetizar ATP via ATP-sintase.","resposta":""},
  {"id":"4074","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Tipos de ecossistemas","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Os principais biomas terrestres brasileiros incluem:","alternativa_a":"Amazonia, Cerrado, Caatinga, Mata Atlantica, Pantanal e Pampa","alternativa_b":"Taiga, Tundra, Savana africana e Floresta temperada","alternativa_c":"Oceanos, Recifes de coral e Manguezais","alternativa_d":"Deserto do Saara, Floresta de bambu e Estepe","alternativa_e":"Selva tropical australiana, Chaparral e Pradaria norte-americana","resposta_correta":"a","explicacao":"O Brasil possui seis biomas terrestres reconhecidos pelo IBGE: Amazonia (maior), Cerrado (segundo maior), Caatinga (semiarido nordestino), Mata Atlantica (litoral), Pantanal (planicie alagavel) e Pampa (extremo sul). Alem desses, ha ecossistemas costeiros (manguezais, restingas, recifes). O Brasil e o pais com maior biodiversidade do planeta.","resposta":""},
  {"id":"4075","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Iluminismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Iluminismo, movimento intelectual do seculo XVIII, caracterizou-se pela:","alternativa_a":"Fe na razao, no progresso e na ciencia como instrumentos de emancipacao humana","alternativa_b":"Valorizacao da fe religiosa sobre a razao","alternativa_c":"Defesa da monarquia absoluta e do direito divino dos reis","alternativa_d":"Rejeicao da ciencia moderna em favor da tradicao","alternativa_e":"Apologia do sistema feudal","resposta_correta":"a","explicacao":"O Iluminismo (ou Ilustracao) foi um movimento filosofico e cultural que pregava a razao, a ciencia, a tolerancia religiosa, os direitos naturais e o progresso humano. Seus principais representantes incluem Voltaire, Rousseau, Montesquieu, Locke e os Enciclopedistas. Influenciou as revolucoes americana e francesa.","resposta":""},
  {"id":"4076","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Segundo Imperio","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Guerra do Paraguai (1864-1870) envolveu o Brasil, Argentina e Uruguai contra o Paraguai. Uma das principais consequencias para o Brasil foi:","alternativa_a":"Fortalecimento do exercito e crescimento do republicanismo e abolicionismo","alternativa_b":"O enfraquecimento do poder militar e manutencao da monarquia","alternativa_c":"A anexacao de territorio paraguaio ao Brasil","alternativa_d":"A alianca permanente com a Argentina","alternativa_e":"O declinio da lavoura cafeeira","resposta_correta":"a","explicacao":"A Guerra do Paraguai fortaleceu o exercito como ator politico, gerando insatisfacao com o Poder Moderador de D. Pedro II. O exercito passou a ter aspiracoes politicas (positivismo militar). Alem disso, a guerra acelerou o movimento abolicionista (muitos escravizados lutaram com promessa de liberdade) e o republicanismo, contribuindo para a crise do Imperio.","resposta":""},
  {"id":"4077","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Cangaco","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O cangaco, movimento de banditismo social que atuou no sertao nordestino no final do seculo XIX e inicio do XX, tinha como lider mais famoso:","alternativa_a":"Virgulino Ferreira da Silva (Lampiao)","alternativa_b":"Antonio Conselheiro","alternativa_c":"Pe. Cicero Romao","alternativa_d":"Jose do Pinho","alternativa_e":"Ze Cangalha","resposta_correta":"a","explicacao":"Lampiao (Virgulino Ferreira da Silva, 1898-1938) foi o mais famoso lider cangaceiro. O cangaco e interpretado por estudiosos como Eric Hobsbawm como 'banditismo social' — rebeldia popular contra a opressao das oligarquias e do coronelismo. O grupo de Lampiao atuou nos sertoes de varios estados nordestinos por decadas.","resposta":""},
  {"id":"4078","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Nazismo e Fascismo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O Holocausto foi o genocidio sistematico de judeus e outras minorias promovido pela Alemanha nazista. Estima-se que foram assassinadas:","alternativa_a":"Cerca de 6 milhoes de judeus, alem de Roma, homossexuais e outros","alternativa_b":"1 milhao de pessoas em total","alternativa_c":"Apenas combatentes militares","alternativa_d":"500 mil pessoas em campos de concentracao","alternativa_e":"Somente lideres politicos opositores","resposta_correta":"a","explicacao":"O Holocausto (Shoah) foi o genocidio de aproximadamente 6 milhoes de judeus (2/3 dos judeus europeus) e entre 5-6 milhoes de outras vitimas (Roma, pessoas com deficiencia, homossexuais, prisioneiros sovieticos, testemunhas de Jeova, opositores politicos). Foi executado pela Alemanha nazista principalmente atraves dos campos de exterminio (Auschwitz, Treblinka, Sobibor etc.).","resposta":""},
  {"id":"4079","tipo":"multipla","disciplina":"Geografia","tema":"Geopolitica","subtema":"Blocos economicos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O Mercosul (Mercado Comum do Sul) e formado originalmente pelos paises:","alternativa_a":"Brasil, Argentina, Uruguai e Paraguai","alternativa_b":"Brasil, Bolivia, Chile e Peru","alternativa_c":"Brasil, Colombia, Venezuela e Mexico","alternativa_d":"Todos os paises sul-americanos","alternativa_e":"Brasil, Argentina, Chile e Uruguai","resposta_correta":"a","explicacao":"O Mercosul foi criado em 1991 pelo Tratado de Assuncao com quatro membros fundadores: Brasil, Argentina, Uruguai e Paraguai. A Venezuela foi suspensa em 2016 (por clausula democratica). Bolivia esta em processo de adesao. E o maior bloco economico da America do Sul, representando cerca de 75% do PIB regional.","resposta":""},
  {"id":"4080","tipo":"multipla","disciplina":"Geografia","tema":"Populacao","subtema":"IDH","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O IDH (Indice de Desenvolvimento Humano) e calculado com base em tres dimensoes:","alternativa_a":"Longevidade, educacao e renda (PIB per capita)","alternativa_b":"PIB, exportacoes e infraestrutura","alternativa_c":"Populacao, territorio e renda","alternativa_d":"Saude, seguranca e educacao","alternativa_e":"Democracia, liberdade de imprensa e renda","resposta_correta":"a","explicacao":"O IDH, criado pelo PNUD em 1990 por Amartya Sen e Mahbub ul Haq, combina tres indicadores: esperanca de vida ao nascer (longevidade/saude), anos de escolaridade (educacao) e Renda Nacional Bruta per capita (renda). Varia de 0 a 1 e classifica paises em IDH muito alto, alto, medio e baixo.","resposta":""},
  {"id":"4081","tipo":"multipla","disciplina":"Geografia","tema":"Meio Ambiente","subtema":"Camada de ozonio","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A destruicao da camada de ozonio e causada principalmente por:","alternativa_a":"Clorofluorcarbonos (CFCs) utilizados em refrigeradores e aerossois","alternativa_b":"CO2 emitido por veiculos","alternativa_c":"Metano produzido por pecuaria","alternativa_d":"Oxidos de nitrogenio de industrias","alternativa_e":"Vapor dagua da evaporacao oceanica","resposta_correta":"a","explicacao":"Os CFCs (clorofluorcarbonos), usados em refrigeradores, ar-condicionado e aerossois, liberam cloro na estratosfera que catalisa a destruicao do ozonio (O3). O Protocolo de Montreal (1987) baniu gradualmente os CFCs. A camada de ozonio protege a Terra da radiacao UV-B, nociva para seres vivos.","resposta":""},
  {"id":"4082","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Sujeito e predicado","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Em 'Chove muito em dezembro no Brasil', o sujeito e:","alternativa_a":"Inexistente — verbo impessoal","alternativa_b":"'Dezembro'","alternativa_c":"'Brasil'","alternativa_d":"'muito'","alternativa_e":"Oculto","resposta_correta":"a","explicacao":"O verbo 'chover' e meteorologico e, quando usado nesse sentido, e impessoal — nao tem sujeito. Orações com sujeito inexistente (ou verbo sem sujeito) ocorrem com verbos que indicam fenomenos naturais (chover, nevar, trovejar) e com 'haver' e 'fazer' no sentido de tempo ou existencia.","resposta":""},
  {"id":"4083","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Tipos de sujeito","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em 'Vende-se apartamento', o sujeito e:","alternativa_a":"Indeterminado — o pronome 'se' indetermina o agente","alternativa_b":"'apartamento' — sujeito simples","alternativa_c":"Inexistente","alternativa_d":"Composto","alternativa_e":"Oculto (subentendido)","resposta_correta":"a","explicacao":"'Vende-se apartamento' e uma voz ativa com sujeito indeterminado (o agente nao e identificado). O 'se' funciona como indice de indeterminacao do sujeito, com verbo na 3a pessoa do singular. Nao confundir com passiva sintetica: 'Vende-se apartamentoS' (com sujeito paciente no plural) seria passiva, com verbo no plural.","resposta":""},
  {"id":"4084","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Figuras de Linguagem","subtema":"Figuras de pensamento","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em 'Que silencio barulhento!', a figura de linguagem presente e:","alternativa_a":"Oxímoro (paradoxo)","alternativa_b":"Metafora","alternativa_c":"Metonimia","alternativa_d":"Hiperbole","alternativa_e":"Eufemismo","resposta_correta":"a","explicacao":"O oxímoro (ou paradoxo) combina palavras ou ideias contraditórias numa mesma expressao, criando um efeito de tensao significativa. 'Silencio barulhento' une silencio e barulho, elementos opostos. Outros exemplos: 'alegre tristeza', 'gelo ardente', 'luz negra'. Difere da antitese que contrasta ideias em proposicoes separadas.","resposta":""},
  {"id":"4085","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Figuras de Linguagem","subtema":"Figuras de palavras","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"'O Brasil marcou tres gols' — o uso de 'Brasil' no lugar de 'selecao brasileira' e um exemplo de:","alternativa_a":"Metonimia","alternativa_b":"Metafora","alternativa_c":"Comparacao","alternativa_d":"Sinestesia","alternativa_e":"Catacrese","resposta_correta":"a","explicacao":"A metonimia e a substituicao de uma palavra por outra com a qual tem relacao de contigüidade, nao de semelhanca (que seria metafora). Aqui o todo (Brasil) substitui a parte (selecao). Outros tipos de metonimia: autor pela obra ('ler Machado'), continente pelo conteudo ('beber um copo'), causa pelo efeito, etc.","resposta":""},
  {"id":"4086","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Antiga","subtema":"Socrates e o metodo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O metodo socratico e composto por duas etapas: ironia e maieutica. A maieutica consiste em:","alternativa_a":"Conduzir o interlocutor ao conhecimento por perguntas que o fazem 'parir' a verdade","alternativa_b":"Ridicularizar o interlocutor para mostrar sua ignorancia","alternativa_c":"Demonstrar a verdade por silogismos formais","alternativa_d":"Observar a natureza para deduzir principios universais","alternativa_e":"Meditar em silencio para alcancar a verdade interior","resposta_correta":"a","explicacao":"O metodo socratico (dialogo filosofico) tem duas fases: (1) Ironia: Socrates finge ignorancia e questiona o interlocutor ate mostrar que seu pretenso conhecimento e contraditorio. (2) Maieutica (arte da parturição): por perguntas sucessivas, Socrates ajuda o interlocutor a 'dar a luz' o conhecimento que ja estava nele implicitamente (reminiscencia, no platonismo posterior).","resposta":""},
  {"id":"4087","tipo":"multipla","disciplina":"Filosofia","tema":"Estetica","subtema":"Arte e beleza","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A estetica como disciplina filosofica autonoma foi fundada por Alexander Baumgarten no seculo XVIII para estudar:","alternativa_a":"O conhecimento sensivel e o julgamento do belo","alternativa_b":"A moral e os valores eticos","alternativa_c":"A logica formal e o silogismo","alternativa_d":"A relacao entre linguagem e realidade","alternativa_e":"A politica e a organizacao do Estado","resposta_correta":"a","explicacao":"Baumgarten cunhou o termo 'estetica' (do grego aisthesis = sensacao, percepcao) em sua obra 'Aesthetica' (1750) para designar a ciencia do conhecimento sensivel e do julgamento do belo. Kant desenvolveu a estetica em 'Critica do Julgamento', distinguindo o belo do sublime. A estetica moderna estuda a experiencia artistica, o gosto, a criatividade e a interpretacao das obras de arte.","resposta":""},
  {"id":"4088","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia Urbana","subtema":"Gentrificacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A gentrificacao urbana refere-se ao processo de:","alternativa_a":"Revitalizacao de areas degradadas que eleva o valor dos imoveis e expulsa moradores originais de baixa renda","alternativa_b":"Construcao de conjuntos habitacionais para populacao de baixa renda","alternativa_c":"Expansao das favelas para areas nobres das cidades","alternativa_d":"Industrializacao de areas anteriormente residenciais","alternativa_e":"Criacao de parques e areas verdes em zonas urbanas","resposta_correta":"a","explicacao":"A gentrificacao (do ingles gentry = pequena nobreza) e o processo de renovacao urbana de bairros populares que atrai populacoes de maior renda e investimentos, elevando o custo de vida e expulsando os moradores originais (displacement). Ocorre no Rio de Janeiro (Lapa, Santa Teresa), Sao Paulo (Vila Madalena) e em cidades globais como Nova York e Londres.","resposta":""},
  {"id":"4089","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia do Crime","subtema":"Anomia","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O conceito de anomia, originalmente desenvolvido por Durkheim e depois por Merton, refere-se a:","alternativa_a":"Estado de desregulacao social onde as normas perdem eficacia sobre o individuo","alternativa_b":"Conjunto de leis penais de uma sociedade","alternativa_c":"Harmonia social perfeita sem conflitos","alternativa_d":"Excesso de normas sociais que oprimem o individuo","alternativa_e":"Processo de integracao social dos imigrantes","resposta_correta":"a","explicacao":"Durkheim introduziu a anomia para descrever situacoes de ruptura normativa (crise economica, desintegracao social) que levam ao descontrole das paixoes individuais e ao aumento do suicidio anomico. Merton reformulou: anomia ocorre quando ha tensao entre metas culturais (ex: sucesso material) e meios legítimos de atingi-las, levando ao desvio.","resposta":""},
  {"id":"4090","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Funcao modular","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O valor de |3 - 7| + |-2| e:","alternativa_a":"6","alternativa_b":"2","alternativa_c":"-2","alternativa_d":"12","alternativa_e":"4","resposta_correta":"a","explicacao":"|3-7| = |-4| = 4. |-2| = 2. Soma = 4 + 2 = 6.","resposta":""},
  {"id":"4091","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Binomio de Newton","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"No desenvolvimento de (x+y)^4, o coeficiente do termo x^2 y^2 e:","alternativa_a":"6","alternativa_b":"4","alternativa_c":"12","alternativa_d":"1","alternativa_e":"8","resposta_correta":"a","explicacao":"Pelo binomio de Newton: C(4,2) = 4!/(2!2!) = 24/4 = 6. O termo e C(4,2) x^2 y^2 = 6x^2y^2.","resposta":""},
  {"id":"4092","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Elasticidade — Lei de Hooke","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma mola tem constante elastica k = 200 N/m. Para comprimi-la 10 cm, precisa-se de uma forca de:","alternativa_a":"20 N","alternativa_b":"2000 N","alternativa_c":"0,2 N","alternativa_d":"200 N","alternativa_e":"2 N","resposta_correta":"a","explicacao":"Lei de Hooke: F = k * x = 200 * 0,1 = 20 N. (10 cm = 0,1 m)","resposta":""},
  {"id":"4093","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Energia potencial elastica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A energia potencial elastica armazenada em uma mola de k = 200 N/m comprimida 10 cm e:","alternativa_a":"1 J","alternativa_b":"20 J","alternativa_c":"0,1 J","alternativa_d":"10 J","alternativa_e":"200 J","resposta_correta":"a","explicacao":"Ep = (1/2) k x^2 = (1/2) x 200 x (0,1)^2 = 100 x 0,01 = 1 J.","resposta":""},
  {"id":"4094","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Calor especifico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Para aquecer 200 g de agua de 20C para 70C, sendo o calor especifico da agua 1 cal/g.C, precisa-se de:","alternativa_a":"10.000 cal","alternativa_b":"14.000 cal","alternativa_c":"1.000 cal","alternativa_d":"200 cal","alternativa_e":"50 cal","resposta_correta":"a","explicacao":"Q = m x c x DeltaT = 200 x 1 x (70-20) = 200 x 50 = 10.000 cal = 10 kcal.","resposta":""},
  {"id":"4095","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Pilhas eletroquimicas","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Numa pilha galvanica (eletroquimica), a oxidacao ocorre no:","alternativa_a":"Anodo (eletrodo negativo na pilha)","alternativa_b":"Catodo (eletrodo positivo)","alternativa_c":"Eletrólito","alternativa_d":"Ponte salina","alternativa_e":"Circuito externo","resposta_correta":"a","explicacao":"Memoria: 'RedCat OxAno'. Reducao ocorre no catodo; oxidacao ocorre no anodo. Na pilha galvanica (espontanea), o anodo e o polo negativo (perde eletrons = oxidacao) e o catodo e o polo positivo (ganha eletrons = reducao). Os eletrons fluem pelo circuito externo do anodo para o catodo.","resposta":""},
  {"id":"4096","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema excretor","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O principal orgao excretor do corpo humano responsavel pela filtragem do sangue e producao de urina e:","alternativa_a":"Rim (rins)","alternativa_b":"Figado","alternativa_c":"Pulmao","alternativa_d":"Intestino grosso","alternativa_e":"Pele","resposta_correta":"a","explicacao":"Os rins filtram o sangue (180 litros/dia nos glomérulos), reabsorvem agua e nutrientes, e excretam residuos metabolicos (ureia, creatinina, amonia) na urina. O nefron e a unidade funcional do rim. A ureia e produzida no figado (ciclo da ureia) e excretada pelos rins.","resposta":""},
  {"id":"4097","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Divisao celular","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A meiose difere da mitose principalmente porque:","alternativa_a":"Produz 4 celulas haploides (n) com variabilidade genetica; mitose produz 2 celulas diploides (2n) identicas","alternativa_b":"Ocorre apenas em celulas tumorais","alternativa_c":"Produz celulas com o dobro do material genetico","alternativa_d":"Nao envolve replicacao do DNA","alternativa_e":"Ocorre em todos os tecidos do corpo adulto","resposta_correta":"a","explicacao":"A meiose e uma divisao celular exclusiva das celulas germinativas (gonadas), que produz 4 celulas haploides (gametas). Envolve dois processos de divisao (meiose I e II) e inclui o crossing-over, que gera variabilidade genetica. A mitose produz 2 celulas diploides identicas a celula-mae, ocorrendo em todas as celulas somaticas para crescimento e regeneracao.","resposta":""},
  {"id":"4098","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Comercio de escravizados transatlantico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O trafico transatlantico de escravizados africanos para as Americas durou aproximadamente:","alternativa_a":"Quatro seculos (seculos XVI ao XIX), com o Brasil sendo o maior destino","alternativa_b":"Apenas o seculo XVI","alternativa_c":"De 1800 a 1850","alternativa_d":"Dois seculos, com os EUA como principal destino","alternativa_e":"De 1492 a 1600","resposta_correta":"a","explicacao":"O trafico atlantico de escravizados durou do seculo XVI ao XIX, com mais de 12 milhoes de africanos deportados para as Americas. O Brasil foi o maior destino individual (cerca de 4,9 milhoes), recebendo escravizados ate 1850 (Lei Eusebia de Queiros). Os principais grupos etnicos traficados incluiam Bantos (Angola/Congo) e Sudaneses (Nigeria/Benin/Senegal).","resposta":""},
  {"id":"4099","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Quilombos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Quilombo dos Palmares, maior quilombo da historia brasileira, localizava-se na regiao:","alternativa_a":"Atual estado de Alagoas, durou do final do seculo XVI ate 1694","alternativa_b":"Estado da Bahia, destruido no seculo XVII","alternativa_c":"Maranhao, destruido em 1840","alternativa_d":"Minas Gerais, apos a Inconfidencia Mineira","alternativa_e":"Para, nas margens do Rio Amazonas","resposta_correta":"a","explicacao":"O Quilombo dos Palmares existiu por cerca de um seculo na Serra da Barriga (atual Alagoas). Chegou a ter entre 20.000 e 30.000 habitantes. Seu lider mais famoso foi Zumbi dos Palmares. Foi destruido em 1694 por forcas coloniais lideradas por Domingos Jorge Velho. O 20 de novembro (data da morte de Zumbi, 1695) e o Dia da Consciencia Negra no Brasil.","resposta":""},
  {"id":"4100","tipo":"multipla","disciplina":"Geografia","tema":"Climatologia","subtema":"El Nino e La Nina","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O fenomeno El Nino e caracterizado pelo:","alternativa_a":"Aquecimento anormal das aguas superficiais do Pacifico equatorial, alterando padroes climaticos globais","alternativa_b":"Resfriamento do Atlantico Sul e aumento de chuvas no Nordeste","alternativa_c":"Esfriamento do Pacifico e estiagem no Sul do Brasil","alternativa_d":"Aumento do nivel dos oceanos por derretimento de geleiras","alternativa_e":"Formacao de furacoes no Atlantico Norte","resposta_correta":"a","explicacao":"O El Nino e o aquecimento anormal das aguas superficiais do Pacifico equatorial central e leste, que ocorre irregularmente a cada 2-7 anos. Altera circulacoes atmosfericas globais: no Brasil causa seca no Nordeste e chuvas excessivas no Sul. La Nina e o fenomeno oposto (resfriamento). Ambos fazem parte do ciclo ENSO (El Nino-Oscilacao Sul).","resposta":""},
  {"id":"4101","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Modernismo — 2a fase","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Carlos Drummond de Andrade e Cecilia Meireles pertencem a qual fase do Modernismo brasileiro?","alternativa_a":"Segunda fase (1930-1945) — geracao de 1930","alternativa_b":"Primeira fase (1922-1930) — semana de arte moderna","alternativa_c":"Terceira fase (1945-1980) — geracao de 45","alternativa_d":"Pre-modernismo (1900-1922)","alternativa_e":"Contemporanea (pos-1980)","resposta_correta":"a","explicacao":"A segunda fase do Modernismo brasileiro (geracao de 30) caracteriza-se por maior maturidade artistica, aprofundamento existencial e social. Na poesia: Carlos Drummond de Andrade, Cecilia Meireles, Vinicius de Moraes, Murilo Mendes. Na prosa: Graciliano Ramos, Jorge Amado, Rachel de Queiroz, Jose Lins do Rego — com forte regionalismo nordestino.","resposta":""},
  {"id":"4102","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Graciliano Ramos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"'Vidas Secas', de Graciliano Ramos, narra a historia de:","alternativa_a":"Uma familia de retirantes nordestinos fugindo da seca — Fabiano, Sinha Vitoria e os filhos","alternativa_b":"Um coronel nordestino e suas relacoes de poder","alternativa_c":"Um intelectual urbano em conflito com a sociedade burguesa","alternativa_d":"A vida de um escravizado no seculo XIX","alternativa_e":"A crise do cangaco e o declinio dos jaguncos","resposta_correta":"a","explicacao":"'Vidas Secas' (1938) e o romance mais conhecido de Graciliano Ramos. Narra o drama de Fabiano (vaqueiro), Sinha Vitoria (sua mulher), os dois filhos sem nome e a cachorra Baleia, fugindo da seca no sertao nordestino. A narrativa e seca como a paisagem, com frases curtas e perspectiva dos personagens simples. E uma das maiores obras do romance social nordestino.","resposta":""},
  {"id":"4103","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Anarquismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O anarquismo, como corrente politica, defende:","alternativa_a":"A eliminacao do Estado e de todas as formas de dominacao e hierarquia coercitiva","alternativa_b":"O fortalecimento do Estado socialista centralizado","alternativa_c":"A democracia representativa liberal","alternativa_d":"O retorno ao Estado minimo neoliberal","alternativa_e":"A teocracia como forma de governo ideal","resposta_correta":"a","explicacao":"O anarquismo (do grego anarchia = sem governo) defende a eliminacao do Estado e de todas as formas de autoridade nao consensual. Seus principais teoricos incluem Pierre-Joseph Proudhon ('A propriedade e um roubo'), Mikhail Bakunin e Piotr Kropotkin. Propoe organizacoes voluntarias, federalismo e cooperacao livre como alternativas a hierarquia estatal.","resposta":""},
  {"id":"4104","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Saude","subtema":"Determinantes sociais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os determinantes sociais da saude referem-se a:","alternativa_a":"Condicoes socioeconomicas, culturais e ambientais que influenciam o estado de saude das populacoes","alternativa_b":"Agentes patogenicos biologicos como bacterias e virus","alternativa_c":"Fatores geneticos hereditarios","alternativa_d":"Politicas de vacinacao e prevencao de doencas","alternativa_e":"Qualidade dos hospitais e servicos medicos","resposta_correta":"a","explicacao":"A Comissao de Determinantes Sociais da Saude da OMS (presidida por Michael Marmot) estabeleceu que as principais causas de doenca e morte nao sao biologicas, mas sociais: renda, educacao, condicoes de moradia, trabalho, alimentacao, acesso a servicos e discriminacao. Populacoes pobres e marginalizadas tem piores indicadores de saude independente de fatores biologicos.","resposta":""},
  {"id":"4105","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Analitica","subtema":"Equacao da reta","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A equacao da reta que passa pelos pontos A(0,3) e B(2,7) e:","alternativa_a":"y = 2x + 3","alternativa_b":"y = 3x + 2","alternativa_c":"y = x + 3","alternativa_d":"y = -2x + 3","alternativa_e":"y = 2x - 3","resposta_correta":"a","explicacao":"Coeficiente angular: m = (7-3)/(2-0) = 4/2 = 2. Equacao: y = 2x + b. Usando A(0,3): 3 = 2(0) + b, b = 3. Logo y = 2x + 3.","resposta":""},
  {"id":"4106","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Area do cilindro","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um cilindro tem raio 3 cm e altura 5 cm. Sua area lateral e (pi=3,14):","alternativa_a":"94,2 cm2","alternativa_b":"47,1 cm2","alternativa_c":"141,3 cm2","alternativa_d":"28,26 cm2","alternativa_e":"188,4 cm2","resposta_correta":"a","explicacao":"Area lateral do cilindro = 2*pi*r*h = 2 x 3,14 x 3 x 5 = 94,2 cm2.","resposta":""},
  {"id":"4107","tipo":"multipla","disciplina":"Fisica","tema":"Termodinamica","subtema":"Maquinas termicas","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Uma maquina termica opera entre uma fonte quente a 500K e uma fria a 250K. Sua eficiencia maxima (Carnot) e:","alternativa_a":"50%","alternativa_b":"25%","alternativa_c":"75%","alternativa_d":"100%","alternativa_e":"30%","resposta_correta":"a","explicacao":"Eficiencia de Carnot: eta = 1 - Tc/Th = 1 - 250/500 = 1 - 0,5 = 0,5 = 50%. E a eficiencia maxima teorica, nao atingida por maquinas reais devido as irreversibilidades.","resposta":""},
  {"id":"4108","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Atomistica","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O numero de massa de um atomo e definido como:","alternativa_a":"Soma do numero de protons e neutrons no nucleo","alternativa_b":"Numero de eletrons na eletrosfera","alternativa_c":"Numero de protons no nucleo","alternativa_d":"Numero de neutrons menos protons","alternativa_e":"Massa do atomo em gramas","resposta_correta":"a","explicacao":"O numero de massa (A) = Z + N, onde Z = numero atomico (protons) e N = numero de neutrons. Exemplo: carbono-12 tem Z=6 protons e N=6 neutrons, logo A=12. O numero de massa nao e a massa atomica real (que e em unidades de massa atomica, u), mas e igual numericamente para isotopos comuns.","resposta":""},
]

